// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.file.Path;

import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo.LeoEvidence;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo.LeoSurfaceKey;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbLeoSurfaceStatsTest {

	@Test
	void fanoutStatsKeepTopKAndQuantileBuckets() {
		LmdbLeoFeedbackConfig config = new LmdbLeoFeedbackConfig(2, 4, 2);
		LmdbLeoSurfaceStats stats = new LmdbLeoSurfaceStats(config);

		stats.recordFanout(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 10L, 100L, 1L);
		stats.recordFanout(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 10L, 110L, 2L);
		stats.recordFanout(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 20L, 5L, 3L);
		stats.recordFanout(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 30L, 7L, 4L);

		assertEquals(2, stats.heavyHitterCount(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT));
		assertTrue(stats.estimateFanout(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 10L).isPresent());
		assertEquals(2, stats.quantileBuckets(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT).size());
		assertTrue(stats.bucketEstimate(1L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 99L).isPresent());
	}

	@Test
	void confidenceRisesAndOutlierCapsSurfaceTrust() {
		LmdbLeoSurfaceStats stats = new LmdbLeoSurfaceStats(LmdbLeoFeedbackConfig.defaultConfig());

		stats.recordFanout(2L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 40L, 50L, 1L);
		double first = stats.estimateFanout(2L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 40L)
				.orElseThrow()
				.confidence();
		stats.recordFanout(2L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 40L, 51L, 2L);
		stats.recordFanout(2L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 40L, 49L, 3L);
		double stable = stats.estimateFanout(2L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 40L)
				.orElseThrow()
				.confidence();
		stats.recordFanout(2L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 40L, 5_000L, 4L);
		double afterOutlier = stats.estimateFanout(2L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 40L)
				.orElseThrow()
				.confidence();

		assertTrue(first <= 0.35d);
		assertTrue(stable > first);
		assertTrue(afterOutlier < 0.75d);
	}

	@Test
	void storePersistsAndResetsOnRevisionMismatch(@TempDir Path tempDir) throws Exception {
		LmdbLeoFeedbackStore store = new LmdbLeoFeedbackStore(tempDir.resolve("leo-surfaces.bin"),
				LmdbLeoFeedbackConfig.defaultConfig());
		LmdbLeoSurfaceStats stats = new LmdbLeoSurfaceStats(LmdbLeoFeedbackConfig.defaultConfig());
		stats.recordFanout(3L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 70L, 12L, 1L);
		store.persist("revision-a", stats);

		LmdbLeoSurfaceStats loaded = store.load("revision-a");
		assertTrue(loaded.estimateFanout(3L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 70L).isPresent());

		LmdbLeoSurfaceStats reset = store.load("revision-b");
		assertFalse(reset.estimateFanout(3L, LmdbLeoSurfaceStats.BoundPosition.SUBJECT, 70L).isPresent());
	}

	@Test
	void providerReturnsPersistedFanoutEvidenceForSurfaceKey() {
		LmdbLeoSurfaceStats stats = new LmdbLeoSurfaceStats(LmdbLeoFeedbackConfig.defaultConfig());
		stats.recordFanout(4L, LmdbLeoSurfaceStats.BoundPosition.OBJECT, 80L, 33L, 1L);
		LmdbLeoSurfaceProvider provider = new LmdbLeoSurfaceProvider(stats);

		LeoEvidence evidence = provider.evidence(LeoSurfaceKey.fanout(4L, "object", 80L)).orElseThrow();

		assertEquals(LeoEvidence.Kind.PERSISTED_FANOUT_HISTOGRAM, evidence.kind());
		assertEquals(33.0d, evidence.rows());
		assertEquals("lmdb-leo-fanout-heavy-hitter", evidence.source());
	}
}
